def validate(args, output):
    n = args[0]
    if not isinstance(output, list) or len(output) != n:
        return False
    if sorted(output) != list(range(1, n+1)):
        return False
    nums = output
    for k in range(len(nums)):
        for i in range(k):
            for j in range(k+1, len(nums)):
                if nums[i] + nums[j] == 2 * nums[k]:
                    return False
    return True

