class Solution:
    def beautifulArray(self, n: int):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(sz):
            if sz == 1:
                return [1]
            odds = [2*x - 1 for x in solve((sz + 1) // 2)]
            evens = [2*x for x in solve(sz // 2)]
            return [x for x in odds + evens if x <= sz]
        return solve(n)

