class Solution:
    def beautifulArray(self, n: int):
        memo = {}
        def build(sz):
            if sz in memo:
                return memo[sz]
            if sz == 1:
                memo[sz] = [1]
                return [1]
            odds = [2*x - 1 for x in build((sz + 1) // 2)]
            evens = [2*x for x in build(sz // 2)]
            result = [x for x in odds + evens if x <= sz]
            memo[sz] = result
            return result
        return build(n)

solutions.javascript:
var beautifulArray = function(n) {
    const memo = new Map();
    function build(sz) {
        if (memo.has(sz)) return memo.get(sz);
        if (sz === 1) { memo.set(1, [1]); return [1]; }
        const odds = build(Math.ceil(sz/2)).map(x => 2*x - 1);
        const evens = build(Math.floor(sz/2)).map(x => 2*x);
        const result = [...odds, ...evens].filter(x => x <= sz);
        memo.set(sz, result);
        return result;
    }
    return build(n);
};
